// [F22] TG-ROUTER 라우팅 판정 노드
// 2026-04-15 v2: @봇이름 접미사 자동 제거 (자동완성 선택 시 /cmd@botname 패턴 지원)
// 2026-04-25 v3: 그룹/포럼 서비스 메시지는 무응답 처리 (General 토픽 오염 방지)
//
// 입력: $input.first().json = 텔레그램 update 원본
// 출력: 원본 update + 메타 필드 (_route, _userId, _chatId, _userName, _hint)

const KNOWN_USERS = {
  '7713811206': { role: 'owner', name: '장지호 대표', tier: 'admin_full' },
  '8606163783': { role: 'owner', name: '원장님 이진선', tier: 'admin_cmd_only' },
  '8312726947': { role: 'staff', name: '이재혁 과장', tier: 'junior_office' }
};
const OWNER_IDS = ['7713811206', '8606163783'];
const GOV_USER_WHITELIST = ['7713811206'];

const GOV_CMDS = ['/검색','/요약','/이벤트','/상태','/신청','/서류','/서식채움',
                  '/search','/summary','/event','/status','/apply','/docs','/fill'];
const HR_CMDS = ['/시작','/start','/menu','/메뉴','/퇴근','/clockout',
                 '/clockin_office','/clockin_remote','/clockin_field'];
const HR_BUTTONS = ['🏢 사업장 출근','🏠 재택 출근','📸 외근 출근','✅ 퇴근'];

const IGNORED_GROUP_CHAT_IDS = ['-5251214343', '-1003917399249'];

function isGroupChat(chat) {
  return Boolean(chat && (chat.type === 'group' || chat.type === 'supergroup'));
}

function shouldIgnoreGroupChat(chatIdValue, chat) {
  return IGNORED_GROUP_CHAT_IDS.indexOf(String(chatIdValue || '')) >= 0 || isGroupChat(chat);
}

// "/cmd@botname" 같은 형식에서 @봇이름 제거하는 헬퍼
function stripBotMention(word) {
  return (word || '').split('@')[0];
}

const update = $input.first().json || {};

let route = 'COLLECT';
let userId = '';
let chatId = '';
let userName = '';
let hint = '';

// 1. callback_query
if (update.callback_query) {
  const cq = update.callback_query;
  userId = String((cq.from && cq.from.id) || '');
  chatId = String((cq.message && cq.message.chat && cq.message.chat.id) || userId);
  userName = (cq.from && cq.from.first_name) || '';
  const data = (cq.data || '').trim();

  if (shouldIgnoreGroupChat(chatId, cq.message && cq.message.chat)) {
    route = 'IGNORE';
    hint = '그룹 callback_query 무응답 처리: ' + chatId;
  } else if (data.indexOf('fa001:') === 0) {
    route = 'FA001B';
    hint = 'FA-001b 강사 등업 콜백';
  } else if (data.indexOf('hr:') === 0) {
    route = 'HR';
    hint = 'HR-001 동의/거부 콜백';
  } else {
    route = 'COLLECT';
    hint = '알 수 없는 콜백: ' + data.slice(0, 30);
  }
}
// 2. message
else if (update.message) {
  const msg = update.message;
  userId = String((msg.from && msg.from.id) || '');
  chatId = String((msg.chat && msg.chat.id) || userId);
  userName = (msg.from && msg.from.first_name) || '';
  const text = (msg.text || '').trim();
  const firstWordRaw = text.split(/\s+/)[0] || '';
  const firstWord = stripBotMention(firstWordRaw).toLowerCase();  // /cmd@botname → /cmd

  if (shouldIgnoreGroupChat(chatId, msg.chat)) {
    route = 'IGNORE';
    hint = '그룹/포럼 메시지 무응답 처리: ' + chatId;
  } else if (HR_BUTTONS.indexOf(text) >= 0) {
    route = 'HR';
    hint = 'HR 버튼: ' + text;
  } else if (HR_CMDS.some(function(c){ return firstWord === c.toLowerCase(); })) {
    route = 'HR';
    hint = 'HR 명령어: ' + firstWord;
  } else if (GOV_CMDS.some(function(c){ return firstWord === c.toLowerCase(); })) {
    if (GOV_USER_WHITELIST.indexOf(userId) >= 0) {
      route = 'GOV';
      hint = '정부지원 명령어: ' + firstWord;
    } else {
      route = 'COLLECT';
      hint = '정부지원 명령어 미허용 사용자: ' + userId;
    }
  } else if (KNOWN_USERS[userId]) {
    const user = KNOWN_USERS[userId];
    if (user.role === 'owner') {
      route = 'FLORA_DM';
      hint = 'Flora DM: ' + user.name;
    } else {
      route = 'HR';
      hint = 'HR 자유텍스트 (재택 업무일지 가능): ' + user.name;
    }
  } else {
    route = 'COLLECT';
    hint = '미등록 user_id: ' + userId;
  }
}
// 3. 기타
else {
  route = 'COLLECT';
  hint = '지원 안 되는 update type';
}

let userTier = 'senior';
if (KNOWN_USERS[userId]) {
  userTier = KNOWN_USERS[userId].tier || 'senior';
}

return [{
  json: Object.assign({}, update, {
    _route: route,
    _userId: userId,
    _chatId: chatId,
    _userName: userName,
    _hint: hint,
    _tier: userTier
  })
}];

// [F22] 미등록 Chat ID 수집 + 알림 포맷
// 2026-04-15
// - 대표 알림 텍스트 + 미등록 사용자 응답 텍스트 준비
// - 실제 전송은 다음 Telegram 노드에서 수행

const item = $input.first().json || {};
const userId = item._userId || '(unknown)';
const chatId = item._chatId || '';
const userName = item._userName || '(이름 없음)';
const hint = item._hint || '';

// 대표에게 보낼 알림 (Chat ID 수집용)
const ownerAlertText = '🆕 [TG-ROUTER] 미등록 사용자 수신\n\n' +
  '이름: ' + userName + '\n' +
  'user_id: ' + userId + '\n' +
  'chat_id: ' + chatId + '\n' +
  'hint: ' + hint + '\n\n' +
  '등록하려면:\n' +
  '1. staff-profiles.md 업데이트\n' +
  '2. NocoDB/플로라 staff 테이블에 telegram_user_id 추가\n' +
  '3. f22-tg-router.json의 KNOWN_USERS에 항목 추가 후 재배포';

// 미등록 사용자에게 보낼 응답
const userReplyText = '안녕하세요 ' + userName + '님 🌸\n\n' +
  '이 봇은 프레스코21 업무용입니다. 아직 등록되지 않은 사용자로 확인됩니다.\n\n' +
  '대표님께 본인의 텔레그램 ID를 전달해 주세요:\n' +
  '  user_id: ' + userId + '\n\n' +
  '등록 완료 후 다시 메시지를 보내주세요. 감사합니다!';

return [{
  json: Object.assign({}, item, {
    ownerAlertText: ownerAlertText,
    userReplyText: userReplyText
  })
}];
